    unset(_formState.errors, ROOT_ERROR_TYPE);

    if (isEmptyObject(_formState.errors)) {
      _subjects.state.next({
        errors: {},
      });
      try {
        await onValid(fieldValues as TTransformedValues, e);
      } catch (error) {
        onValidError = error;
      }
