  const field = get(_fields, name);
  const fieldReference = field && field._f;

  if (fieldReference) {
    const fieldRef = fieldReference.refs
      ? fieldReference.refs[0]
      : fieldReference.ref;

    if (fieldRef.focus) {
      setTimeout(() => {
